<?php
namespace Tests\Feature\Hr;
use App\Models\HrLicense; use App\Models\LegalEntity; use App\Models\User; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Support\Facades\DB; use Tests\TestCase;
class TrainingPagesTest extends TestCase { use RefreshHrDatabase; public function test_training_pages_render():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$u=User::factory()->create(['role_id'=>$role]);$this->actingAs($u);$t=LegalEntity::create(['user_id'=>$u->id,'name'=>'Eğitim','tax_number'=>'5353535353','is_active'=>true]);app(TenantContext::class)->set($t);HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$t->id,'user_id'=>$u->id,'employee_number'=>'TRNP','national_id_encrypted'=>'enc','national_id_hash'=>'training-page','national_id_last_four'=>'0001','first_name'=>'Eğitim','last_name'=>'Sayfa','status'=>'active']);HrLicense::create(['legal_entity_id'=>$t->id,'module_key'=>'egitim','is_active'=>true]);$this->get(route('hr.training'))->assertOk()->assertSee('Eğitim &amp; Gelişim',false);$this->get(route('hr.my-training'))->assertOk()->assertSee('Eğitimlerim');} }
